import fs from "fs";
import path from "path";
import Papa from "papaparse";

/**
 * Returns the absolute path to the reports directory.
 * Works both locally and on Vercel.
 */
function getReportsDirectory() {
  // process.cwd() in Next.js is usually the `dashboard` folder
  return path.join(process.cwd(), "..", "reports");
}

export interface PredictionRow {
  Abbreviation: string;
  Status: string;
  Predicted_Position: string;
  predicted_laptime_xgb_s: string;
}

/**
 * Reads a Markdown file generated by the AI Summarizer.
 */
export function getRaceSummary(year: number, eventDirName: string, roundNum: number): string | null {
  try {
    const filePath = path.join(
      getReportsDirectory(),
      year.toString(),
      "summaries",
      `report_round_${roundNum}.md`
    );
    
    if (!fs.existsSync(filePath)) {
      return null;
    }
    
    return fs.readFileSync(filePath, "utf8");
  } catch (error) {
    console.error("Failed to read race summary:", error);
    return null;
  }
}

/**
 * Reads the predictions CSV file.
 */
export function getRacePredictions(year: number, eventDirName: string): PredictionRow[] | null {
  try {
    const filePath = path.join(
      getReportsDirectory(),
      year.toString(),
      eventDirName,
      "results",
      "predictions.csv"
    );
    
    if (!fs.existsSync(filePath)) {
      return null;
    }
    
    const csvFile = fs.readFileSync(filePath, "utf8");
    const parsed = Papa.parse<PredictionRow>(csvFile, {
      header: true,
      skipEmptyLines: true,
    });
    
    return parsed.data;
  } catch (error) {
    console.error("Failed to read predictions CSV:", error);
    return null;
  }
}
